SELECT c.*, u.avatar as user_avatar, s.name as service_name FROM service_comment c LEFT JOIN user u ON c.user_id = u.id LEFT JOIN service_item s ON c.service_id = s.id
AND (c.user_name LIKE CONCAT('%', #{keyword}, '%') OR c.content LIKE CONCAT('%', #{keyword}, '%') OR s.name LIKE CONCAT('%', #{keyword}, '%'))
AND c.rating = #{rating}
AND c.status = #{status}
ORDER BY c.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM service_comment c LEFT JOIN service_item s ON c.service_id = s.id
AND (c.user_name LIKE CONCAT('%', #{keyword}, '%') OR c.content LIKE CONCAT('%', #{keyword}, '%') OR s.name LIKE CONCAT('%', #{keyword}, '%'))
AND c.rating = #{rating}
AND c.status = #{status}
